// typeof narrowing
function formatValue(value: string | number): string {
  if (typeof value === 'string') {
    return value.toUpperCase(); // TypeScript knows it's a string here
  }
  return value.toFixed(2); // TypeScript knows it's a number here
}

// Discriminated unions (the most powerful narrowing pattern)
interface LoadingState {
  status: 'loading';
}

interface SuccessState {
  status: 'success';
  data: string[];
}

interface ErrorState {
  status: 'error';
  message: string;
}

type RequestState = LoadingState | SuccessState | ErrorState;

function renderState(state: RequestState): string {
  switch (state.status) {
    case 'loading':
      return 'Loading...';
    case 'success':
      return `Found ${state.data.length} items`; // data is available
    case 'error':
      return `Error: ${state.message}`; // message is available
  }
}

// Type guards with 'in' operator
function isUser(value: User | AdminUser): value is AdminUser {
  return 'permissions' in value;
}

interface User {
  id: number;
  name: string;
  email: string;
  password: string;
  createdAt: Date;
}

// Partial<T>: all properties become optional
type UpdateUserInput = Partial<User>;
// { id?: number; name?: string; email?: string; ... }

// Required<T>: all properties become required
type StrictUser = Required<User>;

// Pick<T, K>: select only specific properties
type UserPreview = Pick<User, 'id' | 'name'>;
// { id: number; name: string }

// Omit<T, K>: remove specific properties
type PublicUser = Omit<User, 'password'>;
// { id: number; name: string; email: string; createdAt: Date }

// Record<K, V>: create an object type with specific keys and value types
type Roles = 'admin' | 'editor' | 'viewer';
type RolePermissions = Record<Roles, string[]>;
// { admin: string[]; editor: string[]; viewer: string[] }

// Readonly<T>: all properties become readonly
type FrozenUser = Readonly<User>;

// ReturnType<T>: extract the return type of a function
function fetchUser() {
  return { id: 1, name: 'Alice' };
}
type FetchResult = ReturnType<typeof fetchUser>;
// { id: number; name: string }
